code.C:
#include <stdio.h>
#include <stdint.h>

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        uint64_t n;
        scanf("%llu", &n);
        uint64_t result = (1ULL << n) - 1;
        printf("Case %d: %llu\n", t + 1, result % (1ULL << 33));
    }
    return 0;
}

