code.Java:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            long n = scanner.nextLong();
            long result = (1L << n) - 1;
            System.out.println("Case " + (t + 1) + ": " + (result % (1L << 33)));
        }
    }
}

